/// <summary>
///
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
/// <returns></returns>
public boolean insertEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret = super(_entityCtx, _dataSourceCtx);

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockSetupGroupEntity, FWFTextBlockSetupGroup))
    {
        this.insertUpdateTextBlockSetupGroupParm(_entityCtx, _dataSourceCtx);
    }

    return ret;
}

/// <summary>
///
/// </summary>
/// <param name = "_entityCtx"></param>
/// <param name = "_dataSourceCtx"></param>
/// <returns></returns>
public boolean updateEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    boolean ret = super(_entityCtx, _dataSourceCtx);

    if (_dataSourceCtx.name() == dataEntityDataSourceStr(FWFTextBlockSetupGroupEntity, FWFTextBlockSetupGroup))
    {
        this.insertUpdateTextBlockSetupGroupParm(_entityCtx, _dataSourceCtx);
    }

    return ret;
}

private void insertUpdateTextBlockSetupGroupParm(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    FWFTextBlockSetupGroup          textBlockSetupGroup;
    FWFTextBlockSetupGroupParm      textBlockSetupGroupParm;
    FWFTextBlockSetupGroupEntity    textBlockSetupGroupEntity;

    textBlockSetupGroup       = _dataSourceCtx.getBuffer();
    textBlockSetupGroupEntity = _entityCtx.getEntityRecord();

    textBlockSetupGroupParm = FWFTextBlockSetupGroupParm::find(textBlockSetupGroup.SetupRecId, true);
    textBlockSetupGroupParm.ICCopy                      = textBlockSetupGroupEntity.TextBlockParm_ICCopy;
    textBlockSetupGroupParm.DirectDeliveryCopy		    = textBlockSetupGroupEntity.TextBlockParm_DirectDeliveryCopy;
    textBlockSetupGroupParm.RelatedPOCopy			    = textBlockSetupGroupEntity.TextBlockParm_RelatedPOCopy;
    textBlockSetupGroupParm.Position                    = textBlockSetupGroupEntity.TextBlockParm_Position;
    textBlockSetupGroupParm.PrintOnPurchConfirmation    = textBlockSetupGroupEntity.TextBlockParm_PrintOnPurchConfirmation;
    textBlockSetupGroupParm.PrintOnPurchInvoice         = textBlockSetupGroupEntity.TextBlockParm_PrintOnPurchInvoice;
    textBlockSetupGroupParm.PrintOnPurchPackingSlip     = textBlockSetupGroupEntity.TextBlockParm_PrintOnPurchPackingSlip;
    textBlockSetupGroupParm.PrintOnPurchReceiptsList    = textBlockSetupGroupEntity.TextBlockParm_PrintOnPurchReceiptsList;
    textBlockSetupGroupParm.PrintOnSalesConfirmation    = textBlockSetupGroupEntity.TextBlockParm_PrintOnSalesConfirmation;
    textBlockSetupGroupParm.PrintOnSalesInvoice         = textBlockSetupGroupEntity.TextBlockParm_PrintOnSalesInvoice;
    textBlockSetupGroupParm.PrintOnSalesPackingSlip     = textBlockSetupGroupEntity.TextBlockParm_PrintOnSalesPackingSlip;
    textBlockSetupGroupParm.PrintOnSalesPickingList     = textBlockSetupGroupEntity.TextBlockParm_PrintOnSalesPickingList;
    textBlockSetupGroupParm.PrintOnSalesQuotation       = textBlockSetupGroupEntity.TextBlockParm_PrintOnSalesQuotation;
    textBlockSetupGroupParm.ShowWarning                 = textBlockSetupGroupEntity.TextBlockParm_ShowWarning;
    textBlockSetupGroupParm.SortOrder                   = textBlockSetupGroupEntity.TextBlockParm_SortOrder;
    textBlockSetupGroupParm.PrintOnCustFreeInvoice      = textBlockSetupGroupEntity.TextBlockParm_PrintOnCustFreeInvoice;
    textBlockSetupGroupParm.PrintOnPurchAgreement       = textBlockSetupGroupEntity.TextBlockParm_PrintOnPurchAgreement;
    textBlockSetupGroupParm.PrintOnSalesAgreement       = textBlockSetupGroupEntity.TextBlockParm_PrintOnSalesAgreement;
    textBlockSetupGroupParm.PrintOnProdJobCard		    = textBlockSetupGroupEntity.TextBlockParm_PrintOnProdJobCard;
    textBlockSetupGroupParm.PrintOnProdRouteCard	    = textBlockSetupGroupEntity.TextBlockParm_PrintOnProdRouteCard;
    textBlockSetupGroupParm.PrintOnProdPickList         = textBlockSetupGroupEntity.TextBlockParm_PrintOnProdPickList;
    textBlockSetupGroupParm.PrintOnProjQuotation	    = textBlockSetupGroupEntity.TextBlockParm_PrintOnProjQuotation;
    textBlockSetupGroupParm.PrintOnProjQuotationConfirm = textBlockSetupGroupEntity.TextBlockParm_PrintOnProjQuotationConfirm;
    textBlockSetupGroupParm.InstanceRelationType        = textBlockSetupGroupEntity.TextBlockParm_InstanceRelationType;
    textBlockSetupGroupParm.PrintOnProjInvoice          = textBlockSetupGroupEntity.TextBlockParm_PrintOnProjInvoice;
    textBlockSetupGroupParm.PrintOnPurchReq             = textBlockSetupGroupEntity.TextBlockParm_PrintOnPurchReq;
    textBlockSetupGroupParm.PrintOnPurchRFQCase         = textBlockSetupGroupEntity.TextBlockParm_PrintOnPurchRFQCase;
    textBlockSetupGroupParm.write();

    if (! textBlockSetupGroup.SetupRecId)
    {
        textBlockSetupGroup.selectForUpdate(true);
        textBlockSetupGroup.SetupRecId = textBlockSetupGroupParm.RecId;
        textBlockSetupGroup.update();
    }
}

/// <summary>
///
/// </summary>
public void postLoad()
{
    FWFTextBlockSetupGroupParm   setupParm;

    super();

    setupParm = FWFTextBlockSetupGroupParm::find(this.SetupRecId);
    this.TextBlockParm_ICCopy                      = setupParm.ICCopy;
    this.TextBlockParm_DirectDeliveryCopy		   = setupParm.DirectDeliveryCopy;
    this.TextBlockParm_RelatedPOCopy			   = setupParm.RelatedPOCopy;
    this.TextBlockParm_InstanceRelationType        = setupParm.InstanceRelationType;
    this.TextBlockParm_Position                    = setupParm.Position;
    this.TextBlockParm_PrintOnPurchConfirmation    = setupParm.PrintOnPurchConfirmation;
    this.TextBlockParm_PrintOnPurchInvoice         = setupParm.PrintOnPurchInvoice;
    this.TextBlockParm_PrintOnPurchPackingSlip     = setupParm.PrintOnPurchPackingSlip;
    this.TextBlockParm_PrintOnPurchReceiptsList    = setupParm.PrintOnPurchReceiptsList;
    this.TextBlockParm_PrintOnSalesConfirmation    = setupParm.PrintOnSalesConfirmation;
    this.TextBlockParm_PrintOnSalesInvoice         = setupParm.PrintOnSalesInvoice;
    this.TextBlockParm_PrintOnSalesPackingSlip     = setupParm.PrintOnSalesPackingSlip;
    this.TextBlockParm_PrintOnSalesPickingList     = setupParm.PrintOnSalesPickingList;
    this.TextBlockParm_PrintOnSalesQuotation       = setupParm.PrintOnSalesQuotation;
    this.TextBlockParm_ShowWarning                 = setupParm.ShowWarning;
    this.TextBlockParm_SortOrder                   = setupParm.SortOrder;
    this.TextBlockParm_PrintOnCustFreeInvoice      = setupParm.PrintOnCustFreeInvoice;
    this.TextBlockParm_PrintOnPurchAgreement       = setupParm.PrintOnPurchAgreement;
    this.TextBlockParm_PrintOnSalesAgreement       = setupParm.PrintOnSalesAgreement;
    this.TextBlockParm_PrintOnProdJobCard		   = setupParm.PrintOnProdJobCard;
    this.TextBlockParm_PrintOnProdRouteCard		   = setupParm.PrintOnProdRouteCard;
    this.TextBlockParm_PrintOnProdPickList         = setupParm.PrintOnProdPickList;
    this.TextBlockParm_PrintOnProjQuotation		   = setupParm.PrintOnProjQuotation;
    this.TextBlockParm_PrintOnProjQuotationConfirm = setupParm.PrintOnProjQuotationConfirm;
    this.TextBlockParm_PrintOnProjInvoice          = setupParm.PrintOnProjInvoice;
    this.TextBlockParm_PrintOnPurchReq             = setupParm.PrintOnPurchReq;
    this.TextBlockParm_PrintOnPurchRFQCase          = setupParm.PrintOnPurchRFQCase;

}
